/**
 * @fileoverview GridTable Feature — Pin (freeze) columns mixin.
 *
 * Lazy-loaded when `enablePinning: true` is set in config.
 * Adds ability to pin columns to left or right edges.
 *
 * @module module/GridTable/features/pin
 */

import {
    recalcFixedLeft  as _recalcFixedLeft,
    updatePinRightShift as _updatePinRightShift,
} from '../layout.js';

/**
 * Install the pin feature onto a GridTable ctx bridge.
 *
 * @param {object} ctx — the shared context bridge
 */
export function installPin(ctx) {
    ctx._pinInstalled = true;

    /**
     * Pin a column to a side.
     * @param {string} name — column name
     * @param {'left'|'right'} side
     */
    ctx.pinColumn = (name, side) => {
        ctx.unpinColumn(name);
        if (side === 'left') {
            ctx.pinnedLeft.push(name);
        } else if (side === 'right') {
            ctx.pinnedRight.push(name);
        }
        ctx.recalcFixedLeft();
        ctx.rebuildPool();
        ctx.saveState();
    };

    /**
     * Unpin a column.
     * @param {string} name — column name
     */
    ctx.unpinColumn = (name) => {
        let idx = ctx.pinnedLeft.indexOf(name);
        if (idx >= 0) ctx.pinnedLeft.splice(idx, 1);
        idx = ctx.pinnedRight.indexOf(name);
        if (idx >= 0) ctx.pinnedRight.splice(idx, 1);
        ctx.recalcFixedLeft();
        ctx.rebuildPool();
        ctx.saveState();
    };

    /**
     * Get all pinned columns.
     * @returns {{ left: string[], right: string[] }}
     */
    ctx.getPinnedColumns = () => ({
        left: [...ctx.pinnedLeft],
        right: [...ctx.pinnedRight],
    });
}

export default installPin;
